// MatchOperation returns the operation name and extracted path parameters for
// the given HTTP method and URI path. It returns ("", nil) if no route matches.
func MatchOperation(method, path string) (string, PathParams) {
	for _, route := range OperationRoutes {
		if route.Method != method {
			continue
		}
		if params, ok := matchURI(route.Pattern, path); ok {
			return route.Operation, params
		}
	}
	return "", nil
}

// matchURI matches a URI path against a pattern that may contain {Label} and
// {Label+} (greedy) segments. Returns the extracted parameters and true on
// match, or nil and false otherwise.
func matchURI(pattern, path string) (PathParams, bool) {
	patParts := splitPath(pattern)
	pathParts := splitPath(path)

	params := PathParams{}
	pi := 0
	for i, pat := range patParts {
		if strings.HasPrefix(pat, "{") && strings.HasSuffix(pat, "+}") {
			// Greedy label: consumes all remaining path segments.
			label := pat[1 : len(pat)-2]
			if pi >= len(pathParts) {
				return nil, false
			}
			params[label] = joinPath(pathParts[pi:])
			pi = len(pathParts)
			// Greedy must be the last pattern segment.
			if i != len(patParts)-1 {
				return nil, false
			}
		} else if strings.HasPrefix(pat, "{") && strings.HasSuffix(pat, "}") {
			// Single-segment label.
			label := pat[1 : len(pat)-1]
			if pi >= len(pathParts) {
				return nil, false
			}
			params[label] = pathParts[pi]
			pi++
		} else {
			// Literal segment.
			if pi >= len(pathParts) || pathParts[pi] != pat {
				return nil, false
			}
			pi++
		}
	}
	if pi != len(pathParts) {
		return nil, false
	}
	return params, true
}

// splitPath splits a URI path into non-empty segments.
func splitPath(path string) []string {
	parts := strings.Split(strings.Trim(path, "/"), "/")
	out := parts[:0]
	for _, p := range parts {
		if p != "" {
			out = append(out, p)
		}
	}
	return out
}

// joinPath joins path segments back with "/" separators.
func joinPath(parts []string) string {
	return strings.Join(parts, "/")
}
